public class ModPaintings {
    public static final PaintingVariant CUSTOM_PAINTING = new PaintingVariant(16, 16);
    public static void register() {
        Registry.register(Registries.PAINTING_VARIANT, new Identifier("modid", "custom_painting"), CUSTOM_PAINTING);
    }
}

ItemStack painting = new ItemStack(Items.PAINTING);
NbtCompound nbt = painting.getOrCreateNbt();
NbtCompound entityTag = new NbtCompound();
entityTag.putString("variant", "modid:custom_painting");
nbt.put("EntityTag", entityTag);

PaintingEntity painting = new PaintingEntity(EntityType.PAINTING, world);
painting.setPosition(x, y, z);
painting.setMotive(ModPaintings.CUSTOM_PAINTING);
world.spawnEntity(painting);
